        _reentrancyLock = true;
        _;
        _reentrancyLock = false;
    }

    constructor(uint256 price_, uint256 maxSupply_) {
        _owner = msg.sender;
        _price = price_;
        _maxSupply = maxSupply_;
        _totalSupply = 0;
    }

    function currentState() public view returns (State) {
        return _currentState;
    }

    function startPresale() public onlyOwner {
        require(_currentState == State.CLOSED, "Already started");
        _currentState = State.PRESALE;
    }

    function startPublicSale() public onlyOwner {
        require(_currentState == State.PRESALE, "Not presale");
        _currentState = State.PUBLIC;
    }

    function price() public view returns (uint256) {
        return _price;
    }

    function totalSupply() public view returns (uint256) {
        return _totalSupply;
    }

    function maxSupply() public view returns (uint256) {
        return _maxSupply;
    }

    function claimedWhitelistStatus(address account) public view returns (bool) {
        return _whitelistStatus[account];
    }

    function mintNFT() external payable nonReentrant {
        require(_currentState == State.PRESALE, "Not presale");
        require(msg.value == _price, "Incorrect payment");
        require(!_whitelistStatus[msg.sender], "Already claimed");
        require(_totalSupply + 1 <= _maxSupply, "Exceeds max supply");

        _whitelistStatus[msg.sender] = true;
        _totalSupply += 1;
    }

