        require(_currentState == State.PUBLIC, "Not public sale");
        require(amount > 0, "Amount must be greater than zero");
        require(msg.value == amount * _price, "Incorrect payment");
        require(_totalSupply + amount <= _maxSupply, "Exceeds max supply");

        _totalSupply += amount;
    }
